<?php namespace Blue\Controllers; use Blue\Core\Database; use Blue\Core\View;
class DashboardController { public function index(){ $stats=[ 'Modules'=>Database::one('SELECT COUNT(*) c FROM modules')['c']??0, 'Records'=>Database::one('SELECT COUNT(*) c FROM module_records')['c']??0, 'Settings'=>Database::one('SELECT COUNT(*) c FROM app_settings')['c']??0, 'Audit Logs'=>Database::one('SELECT COUNT(*) c FROM audit_logs')['c']??0 ]; View::render('dashboard/index',['title'=>'Dashboard','stats'=>$stats,'appTitle'=>'BlueHR Human Resource Platform','tagline'=>'Modular HRIS, Payroll, Approval, and People Analytics']); } }
